import React, { useCallback, useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

const Sidebar = () => {
  const [isModalOpen, setModalState] = useState(false);
  const [projects, setProjects] = useState([]);
  const [paramsWindow, setParamsWindow] = useState(
    window.location.pathname.slice(1)
  );
  const [newProject, setNewProject] = useState({ title: "", description: "" });

  useEffect(() => {
    projectData();
    document.addEventListener("projectUpdate", () => {
      projectData();
    });
    return () => {
      document.removeEventListener("projectUpdate", {}, false);
    };
  }, []);

  const handleLocation = (e) => {
    setParamsWindow(new URL(e.currentTarget.href).pathname.slice(1));
  };

  const openModal = useCallback(() => {
    setModalState(true);
  }, []);

  const closeModal = useCallback(() => {
    setModalState(false);
    setNewProject({ title: "", description: "" }); // Reset input fields
  }, []);

  const projectData = () => {
    axios.get("http://localhost:9000/projects/").then((res) => {
      setProjects(res.data);
    });
  };

  const handleAddProject = () => {
    if (!newProject.title.trim()) return; // Prevent empty title

    axios.post("http://localhost:9000/projects/", newProject).then((res) => {
      setProjects([...projects, res.data]); // Update UI dynamically
      closeModal();
    });
  };

  return (
    <div className="sidebar flex flex-col min-h-screen w-64 bg-gradient-to-b from-blue-800 to-purple-900 text-white shadow-lg">
      {/* Sidebar Header */}
      <div className="sidebar-header flex items-center justify-between p-4 border-b border-blue-700">
        <span className="text-lg font-semibold">Projects</span>
        <button onClick={openModal} className="bg-white text-blue-500 p-2 rounded-full hover:bg-gray-300 transition">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6">
            <path fillRule="evenodd" d="M12 5.25a.75.75 0 01.75.75v5.25H18a.75.75 0 010 1.5h-5.25V18a.75.75 0 01-1.5 0v-5.25H6a.75.75 0 010-1.5h5.25V6a.75.75 0 01.75-.75z" clipRule="evenodd" />
          </svg>
        </button>
      </div>

      {/* Project List */}
      <ul className="overflow-y-auto flex-1 p-2">
        {projects.map((project, index) => (
          <Link key={index} to={project._id} onClick={(e) => handleLocation(e)}>
            <li
              className={`px-5 py-2 mb-1 transition-all rounded-lg cursor-pointer ${
                paramsWindow === project._id
                  ? "bg-indigo-500 text-white font-medium"
                  : "text-gray-300 hover:bg-indigo-700 hover:text-white"
              }`}
            >
              {project.title}
            </li>
          </Link>
        ))}
      </ul>

      {/* Add Project Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
          <div className="bg-white p-6 rounded-lg shadow-lg w-96">
            <h2 className="text-lg font-semibold mb-4 text-gray-800">Add New Project</h2>
            <input
              type="text"
              placeholder="Project Name"
              className="w-full p-2 mb-3 border border-gray-300 rounded"
              value={newProject.title}
              onChange={(e) => setNewProject({ ...newProject, title: e.target.value })}
            />
            <textarea
              placeholder="Project Description"
              className="w-full p-2 mb-3 border border-gray-300 rounded"
              value={newProject.description}
              onChange={(e) => setNewProject({ ...newProject, description: e.target.value })}
            />
            <div className="flex justify-end space-x-2">
              <button onClick={closeModal} className="px-4 py-2 bg-gray-500 text-white rounded hover:bg-gray-600">
                Cancel
              </button>
              <button onClick={handleAddProject} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700">
                Add
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;
